local gameTimeToday = 0
local secondsLeft = 86400
local timerKey
local isGameOver

local function updateExchangeInfo()
    if isGameOver then
        return
    end
    local data = {
        gameTimeToday = gameTimeToday,
        secondsLeft = secondsLeft
    }
    ClientHelper.callAppJsonFunction("updateExchangeInfo", { data = data })
end

ExchangeHelper = {}

function ExchangeHelper:init()
    Listener.registerCallBack(GameActionTriggerEvent, function(_type, params)
        if _type ~= 10001 then
            return
        end
        local success = false
        success, params = pcall(json.decode, params)
        if not success then
            LogUtil.log("[onGameActionTrigger][result]=" .. params, LogUtil.LogLevel.Error)
            return
        end
        if type(params.functionName) ~= "string" then
            LogUtil.log("[onGameActionTrigger]func is not string.", LogUtil.LogLevel.Error)
            return
        end
        if not ClientNetwork.Instance():isAlive() then
            ClientHelper.callAppJsonFunction("exchangeReceiveResult", json.decode({ code = 1005, message = "disconnected from the server.", data = {} }))
            return
        end
        if params.functionName == "exchangeReceive" then
            PacketSender:sendLuaCommonData("ExchangeReceive", params.data)
        end
    end)
    CommonDataEvents:registerCallBack("ExchangeTodayInfo", function(data)
        local builder = DataBuilder.new():fromData(data)
        gameTimeToday = builder:getNumberParam("gameTimeToday") or 0
        secondsLeft = builder:getNumberParam("secondsLeft") or 86400
        updateExchangeInfo()
        LuaTimer:cancel(timerKey)
        timerKey = LuaTimer:scheduleTimer(function()
            secondsLeft = secondsLeft - 60
            if secondsLeft <= 0 then
                gameTimeToday = 60 - secondsLeft
                secondsLeft = 86400 + secondsLeft
            else
                gameTimeToday = gameTimeToday + 60
            end
            updateExchangeInfo()
        end, 60 * 1000)
    end)
    CommonDataEvents:registerCallBack("ExchangeReceiveResult", function(data)
        ClientHelper.callAppJsonFunction("exchangeReceiveResult", json.decode(data))
    end)
end

function ExchangeHelper:cancelExchangeTimer()
    isGameOver = true
    LuaTimer:cancel(timerKey)
end
